import{_ as n,o as t,c as i,ae as a}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Improved Single Sign-On (SSO) Experience","description":"","frontmatter":{"title":"Improved Single Sign-On (SSO) Experience","slug":"improved-single-sign-on-sso-experience"},"headers":[],"relativePath":"account-hub/improved-single-sign-on-sso-experience.md","filePath":"account-hub/improved-single-sign-on-sso-experience.md"}'),r={name:"account-hub/improved-single-sign-on-sso-experience.md"};function o(s,e,l,u,c,g){return t(),i("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch has upgraded our single sign-on (SSO) infrastructure by migrating to Auth0, an industry-leading identity management platform.</p><p>This change enhances security, improves reliability, and provides a better user experience during login.</p><h2 id="migration-deadline-january-2026" tabindex="-1">Migration deadline: January 2026 <a class="header-anchor" href="#migration-deadline-january-2026" aria-label="Permalink to &quot;Migration deadline: January 2026&quot;">​</a></h2><p><strong>Important</strong>: If you currently use Branch SSO, you must migrate to the new Auth0-based system by January 2026. Your existing SSO integration will continue working until then, giving you time to plan your migration.</p><h2 id="what-s-changing" tabindex="-1">What’s changing? <a class="header-anchor" href="#what-s-changing" aria-label="Permalink to &quot;What’s changing?&quot;">​</a></h2><p>We&#39;ve built a completely new SSO system using Auth0 to enhance security and streamline user management.</p><ul><li><strong>Migration required for new experience</strong>: To take advantage of the improved experience, enterprise customers with an existing Branch SSO integration must migrate to the new Auth0-based system.</li><li><strong>New configuration page</strong>: A new Auth0 configuration page is now available in the Branch Dashboard to guide you through the setup/migration process.</li><li><strong>No impact to current login methods</strong>: Your existing SSO integration will continue to function without interruption (<strong>until January 2026</strong>) as you plan your migration. Also, customers not using SSO can continue to log in with a username and password.</li><li><strong>No downtime</strong>: The migration process is designed to be seamless, with no system downtime.</li></ul><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><p>This upgrade offers several key benefits:</p><ul><li><strong>Improved user experience</strong>: The new integration enables access to our redesigned and more intuitive user interface.</li><li><strong>Simplified user management</strong>: Easily provision and deprovision your Branch user accounts.</li><li><strong>Trusted and secure</strong>: Auth0 is a trusted, industry-leading vendor for authentication and authorization.</li></ul><h2 id="who-can-access-the-new-system" tabindex="-1">Who can access the new system? <a class="header-anchor" href="#who-can-access-the-new-system" aria-label="Permalink to &quot;Who can access the new system?&quot;">​</a></h2><p>The new Auth0 SSO is available now for all enterprise customers, including:</p><ul><li>Current SSO users who need to migrate.</li><li>Enterprise customers who want to start using SSO.</li><li>New enterprise customers setting up SSO.</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>Branch SSO is not available for self-serve customers.</p></div><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><p>To get started with Auth0, please see our new guide: <a href="./configure-sso-with-auth0.html">Configure SSO With Auth0</a>. These same steps also apply to customers using our legacy SSO offering with an IdP like Okta.</p>',17)])])}const m=n(r,[["render",o]]);export{d as __pageData,m as default};
